sp_widget.client_script:
function(spUtil, $location) {
	/* widget controller */

	//AA - STRY0028805
	var c = this;
	c.reason = '';
	c.confirmCancel = "";
	$('#uiNotificationContainer').css("z-index","1000000");
	c.submit = function(){
		c.data.submit = true;
		c.data.reason = c.reason;
		spUtil.addInfoMessage("The task has been canceled");
		c.server.update();
		location.reload();
	};

}

sp_widget.script:
(function($sp, input, data, options, gs) {
	/* populate the 'data' object */
	/* e.g., data.table = $sp.getValue('table'); */

	data.submit = false;
	data.uiAction = '';
	data.taskNumber = '';
	var currentUser = gs.getUserDisplayName();
	if(input){
		data.children = input.numberOfChildren;
		data.taskNumber = input.taskNumber;
		if(input.taskId){
			data.taskId = input.taskId;
		}
		if(input.submit == true){
			var gr = new GlideRecord('x_153465_discovert_route_task_instance'); //KT - STRY0063650
			gr.addQuery('sys_id', data.taskId );
			gr.query();
			if(gr.next()){
				gr.u_cancellation_reason = input.reason;
				gr.work_notes = "This task has been cancelled by: " + currentUser + "\nCancellation Reason: " + input.reason;
				gr.state = 7;
				gr.update();
			}
		}
	}
})($sp, input, data, options, gs);
